import 'react-multi-carousel/lib/styles.css'
import Carousel from 'react-multi-carousel'
import meter1 from "../assets/images/meter1.png"
import meter2 from "../assets/images/meter2.png"
import meter3 from "../assets/images/meter3.png"
import meter4 from "../assets/images/meter4.png"
import SkillBg from "../assets/images/skillbg.jpg"

export const Skills = () => {
  const responsive = {
    superLargeDesktop: {
      // the naming can be any, depends on you.
      breakpoint: { max: 4000, min: 3000 },
      items: 5
    },
    desktop: {
      breakpoint: { max: 3000, min: 1024 },
      items: 3
    },
    tablet: {
      breakpoint: { max: 1024, min: 464 },
      items: 2
    },
    mobile: {
      breakpoint: { max: 464, min: 0 },
      items: 1
    }
  };

  return (
    <section className="skill" id="skills">
      <div className="container">
        <div className="row">
          <div className="col-12">
            <div className="skill-bx wow zoomIn">
              <h2>Skills</h2>
              <p>Quick Overview of my skill-level</p>
              <Carousel responsive={responsive} infinite={true} className="owl-carousel owl-theme skill-slider">
                <div className="item">
                  <img src={meter1} alt="Image" />
                  <h5>Java</h5>
                </div>
                <div className="item">
                  <img src={meter1} alt="Image" />
                  <h5>Html</h5>
                </div>
                <div className="item">
                  <img src={meter1} alt="Image" />
                  <h5>Css</h5>
                </div>
                <div className="item">
                  <img src={meter1} alt="Image" />
                  <h5>JavaScript</h5>
                </div>
                <div className="item">
                  <img src={meter1} alt="Image" />
                  <h5>SQL</h5>
                </div>
                <div className="item">
                  <img src={meter1} alt="Image" />
                  <h5>React</h5>
                </div>
                <div className="item">
                  <img src={meter1} alt="Image" />
                  <h5>NodeJs</h5>
                </div>
                <div className="item">
                  <img src={meter1} alt="Image" />
                  <h5>3D-Modeling</h5>
                </div>
                <div className="item">
                  <img src={meter1} alt="Image" />
                  <h5>Web Development</h5>
                </div>
                <div className="item">
                  <img src={meter1} alt="Image" />
                  <h5>Software Development</h5>
                </div>
              </Carousel>
            </div>
          </div>
        </div>
      </div>
    </section>
  )
}

